module top_module(
    input [3:0] data_in,
    input [1:0] shift_amount,
    input direction,
    output [3:0] data_out
);reg [3:0] shifted_data;

    always @(*) begin
        if (direction == 1'b0) // shift right
            shifted_data = data_in >> shift_amount;
        else // shift left
            shifted_data = data_in << shift_amount;
    end

    assign data_out = shifted_data;

  always @(*) begin
    if (1'b0) begin
      if (shift_amount == 2'b00) begin
        shifted_data <= data_in;
      end else if (shift_amount == 2'b01) begin
        shifted_data <= {1'b0, data_in[3:1], 1'b0};
      end else if (shift_amount == 2'b10) begin
        shifted_data <= {data_in[2:0], 1'b0, 1'b0};
      end else if (shift_amount == 2'b11) begin
        shifted_data <= {1'b0, data_in[3:2], 1'b0, 1'b0};
      end
    end
  end

endmodule

